15.     public TicketClassifierService(string dataPath)
16.     {
17.         _mlContext = new MLContext(seed: 42);
18. 
19.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
20.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
21. 
22.         var trainTestSplit = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);
23. 
24.         var pipeline = _mlContext.Transforms.Conversion
25.                 .MapValueToKey("Label", nameof(TicketData.Category))
26.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
27.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
28.             .Append(_mlContext.Transforms.Concatenate("Features",
29.                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
30.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
31.             .AppendCacheCheckpoint(_mlContext)
32.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
33.                 labelColumnName: "Label", featureColumnName: "Features"))
34.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
35. 
36.         _model = pipeline.Fit(trainTestSplit.TrainSet);
37.         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
38. 
39.         // Extract label names in key order
40.         var labelColumn = trainTestSplit.TrainSet.Schema["Label"];
41.         VBuffer<ReadOnlyMemory<char>> labels = default;
42.         labelColumn.GetKeyValues(ref labels);
43.         _categoryLabels = labels.DenseValues().Select(l => l.ToString()).ToArray();
44. 
45.         // Evaluate
46.         var predictions = _model.Transform(trainTestSplit.TestSet);
47.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
48. 
49.         var perCategory = new List<CategoryMetric>();
50.         for (int i = 0; i < _categoryLabels.Length; i++)
51.         {
52.             perCategory.Add(new CategoryMetric
53.             {
54.                 Category = _categoryLabels[i],
55.                 Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
56.                 Recall = metrics.MacroAccuracy
57.             });
58.         }
59. 
60.         // Re-evaluate on full dataset for per-class precision/recall via confusion matrix
61.         var fullPredictions = _model.Transform(dataView);
62.         var fullMetrics = _mlContext.MulticlassClassification.Evaluate(fullPredictions, labelColumnName: "Label");
63.         var confusionMatrix = fullMetrics.ConfusionMatrix;
64. 
65.         var perCategoryDetailed = new List<CategoryMetric>();
66.         for (int i = 0; i < _categoryLabels.Length; i++)
67.         {
68.             var precisions = confusionMatrix.PerClassPrecision;
69.             var recalls = confusionMatrix.PerClassRecall;
70.             perCategoryDetailed.Add(new CategoryMetric
71.             {
72.                 Category = _categoryLabels[i],
73.                 Precision = i < precisions.Count ? precisions[i] : 0,
74.                 Recall = i < recalls.Count ? recalls[i] : 0
75.             });
76.         }
77. 
78.         _evaluationMetrics = new EvaluationMetrics
79.         {
80.             MacroAccuracy = metrics.MacroAccuracy,
81.             MicroAccuracy = metrics.MicroAccuracy,
82.             LogLoss = metrics.LogLoss,
83.             LogLossReduction = metrics.LogLossReduction,
84.             PerCategory = perCategoryDetailed
85.         };
86.     }
