 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketClassifierService
 {
     private readonly MLContext _mlContext;
     private readonly ITransformer _model;
     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
     private readonly string[] _categoryLabels;
     private readonly EvaluationMetrics _evaluationMetrics;

     public TicketClassifierService(string dataPath)
     {
         _mlContext = new MLContext(seed: 42);

         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         var trainTestSplit = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

         var pipeline = _mlContext.Transforms.Conversion
                 .MapValueToKey("Label", nameof(TicketData.Category))
             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features",
                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .AppendCacheCheckpoint(_mlContext)
             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                 labelColumnName: "Label", featureColumnName: "Features"))
             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

         _model = pipeline.Fit(trainTestSplit.TrainSet);
         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

         // Extract label names in key order
         var labelColumn = trainTestSplit.TrainSet.Schema["Label"];
         VBuffer<ReadOnlyMemory<char>> labels = default;
         labelColumn.GetKeyValues(ref labels);
         _categoryLabels = labels.DenseValues().Select(l => l.ToString()).ToArray();

         // Evaluate
         var predictions = _model.Transform(trainTestSplit.TestSet);
         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

         var perCategory = new List<CategoryMetric>();
         for (int i = 0; i < _categoryLabels.Length; i++)
         {
             perCategory.Add(new CategoryMetric
             {
                 Category = _categoryLabels[i],
                 Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
                 Recall = metrics.MacroAccuracy
             });
         }

         // Re-evaluate on full dataset for per-class precision/recall via confusion matrix
         var fullPredictions = _model.Transform(dataView);
         var fullMetrics = _mlContext.MulticlassClassification.Evaluate(fullPredictions, labelColumnName: "Label");
         var confusionMatrix = fullMetrics.ConfusionMatrix;

         var perCategoryDetailed = new List<CategoryMetric>();
         for (int i = 0; i < _categoryLabels.Length; i++)
         {
             var precisions = confusionMatrix.PerClassPrecision;
             var recalls = confusionMatrix.PerClassRecall;
             perCategoryDetailed.Add(new CategoryMetric
             {
                 Category = _categoryLabels[i],
                 Precision = i < precisions.Count ? precisions[i] : 0,
                 Recall = i < recalls.Count ? recalls[i] : 0
             });
         }

         _evaluationMetrics = new EvaluationMetrics
         {
             MacroAccuracy = metrics.MacroAccuracy,
             MicroAccuracy = metrics.MicroAccuracy,
             LogLoss = metrics.LogLoss,
             LogLossReduction = metrics.LogLossReduction,
             PerCategory = perCategoryDetailed
         };
     }

     public PredictionResponse Predict(TicketRequest request)
     {
         var prediction = _predictionEngine.Predict(new TicketData
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         });

         var probabilities = new Dictionary<string, float>();
         for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
         {
             probabilities[_categoryLabels[i]] = prediction.Score[i];
         }

         return new PredictionResponse
         {
             PredictedCategory = prediction.Category,
             Probabilities = probabilities
         };
     }

     public EvaluationMetrics GetEvaluationMetrics() => _evaluationMetrics;
 }

